arguments.command:
# The SGen worker $d.147 entries are ARM mapping symbols - let's find actual functions
# using nm to find nearest function symbols for those addresses
# Need aarch64 cross tools or readelf
readelf -sW /tmp/libmonosgen-debug.so | awk '$2 != "" && $4 == "FUNC"' | \
  awk '{printf "0x%s %s\n", $2, $8}' | sort | \
  awk -v a1=0x2f4b20 -v a2=0x2f4c84 '
  {
    addr = strtonum($1)
    name = $2
    if (addr <= strtonum(a1)) { f1 = name; o1 = addr }
    if (addr <= strtonum(a2)) { f2 = name; o2 = addr }
  }
  END {
    printf "0x2f4b20 -> %s+0x%x\n", f1, strtonum(a1)-o1
    printf "0x2f4c84 -> %s+0x%x\n", f2, strtonum(a2)-o2
  }'

