toolCalls.args:
{"command": "# Let's try objdump to find the function containing each address
# First extract all FUNC symbols sorted by address
readelf -sW /tmp/libmonosgen-debug.so | \
  grep -E 'FUNC\s+(GLOBAL|LOCAL|WEAK)' | \
  awk '{printf "%s %s %s\n", $2, $3, $8}' | sort | \
  awk -v a1="2f4b20" -v a2="2f4c84" '
  BEGIN { t1=strtonum("0x"a1); t2=strtonum("0x"a2) }
  {
    addr=strtonum("0x"$1); size=strtonum("0x"$2); name=$3
    if (addr <= t1 && t1 < addr+size) printf "0x%s -> %s+0x%x\n", a1, name, t1-addr
    if (addr <= t2 && t2 < addr+size) printf "0x%s -> %s+0x%x\n", a2, name, t2-addr
  }' | sort -u", "description": "Find containing functions for SGen worker addresses", "initial_wait": 15}

