{"command": "# Look for SGen/GC-related symbols near the SGen worker addresses
readelf -sW /tmp/libmonosgen-debug.so | grep -v '\$[dxta]' | \
  awk '$4 == "FUNC" && $3 != "0" {addr=strtonum("0x"$2); size=strtonum($3); end=addr+size; printf "0x%08x-0x%08x %s\n", addr, end, $8}' | \
  sort | awk '{
    split($1,r,"-"); lo=strtonum(r[1]); hi=strtonum(r[2]); name=$2
    if (lo <= 0x2f4b20 && 0x2f4b20 < hi) printf "0x2f4b20 in %s (0x%x+0x%x)\n", name, lo, 0x2f4b20-lo
    if (lo <= 0x2f4c84 && 0x2f4c84 < hi) printf "0x2f4c84 in %s (0x%x+0x%x)\n", name, lo, 0x2f4c84-lo
  }'", "description": "Find SGen functions containing addresses", "initial_wait": 15}

arguments.command:
# Check what functions are around the SGen worker addresses
readelf -sW /tmp/libmonosgen-debug.so | grep -v '\$[dxta]' | \
  awk '$4 == "FUNC" {printf "0x%s %s\n", $2, $8}' | sort | \
  awk '{addr=strtonum($1); name=$2; 
    if (addr <= 0x2f4b20) { prev_addr=addr; prev_name=name }
    if (addr > 0x2f4b20 && !found1) { printf "0x2f4b20 between %s (0x%x, +0x%x) and %s (0x%x)\n", prev_name, prev_addr, 0x2f4b20-prev_addr, name, addr; found1=1 }
    if (addr <= 0x2f4c84) { prev_addr2=addr; prev_name2=name }
    if (addr > 0x2f4c84 && !found2) { printf "0x2f4c84 between %s (0x%x, +0x%x) and %s (0x%x)\n", prev_name2, prev_addr2, 0x2f4c84-prev_addr2, name, addr; found2=1 }
  }'

